function parseUser(jsonString) {
  try {
    let user = JSON.parse(jsonString);
    console.log('Name:', user.name);
    return user;
  } catch (error) {
    console.log('Invalid JSON provided');
    console.log('Error details:', error.message);
    return null;
  } finally {
    console.log('Parse attempt finished');
  }
}

parseUser('{"name": "Alice"}');
// Expected output: Name: Alice
// Expected output: Parse attempt finished

parseUser('not-json');
// Expected output: Invalid JSON provided
// Expected output: Parse attempt finished
